export { SpotlightText } from "./SpotlightText";
export type {
  SpotlightTextProps,
  SpotlightTextTheme,
  SpotlightGlowColors,
} from "./types";

"use client";

import { useMemo, type CSSProperties, type ReactNode } from "react";
import { cn } from "../../lib/utils";
import {
  buildBulbGlowGradient,
  useBulbPositions,
  useSpotlightHover,
} from "./hooks/useSpotlightHover";
import { SPOTLIGHT_THEMES } from "./themes";
import type { SpotlightTextProps } from "./types";

const DEFAULT_FONT_SIZE = "clamp(4rem, 15vw, 11.25rem)";
const BULB_CHARS = new Set(["i", "j"]);
/** Sits on the ascender dot — tuned slightly above center of the glyph cap */
const BULB_TOP = "0.16em";

function resolveFontSize(fontSize: string | number | undefined): string {
  if (fontSize === undefined) return DEFAULT_FONT_SIZE;
  return typeof fontSize === "number" ? `${fontSize}px` : fontSize;
}

function renderCharacters(
  text: string,
  options: {
    showBulb: boolean;
    bulbColor: string;
    isActive: boolean;
    glowOnly?: boolean;
  }
): ReactNode[] {
  const { showBulb, bulbColor, glowOnly = false } = options;
  const chars: ReactNode[] = [];

  for (let index = 0; index < text.length; index++) {
    const char = text[index]!;

    if (showBulb && BULB_CHARS.has(char)) {
      chars.push(
        <span key={`${char}-${index}`} className="relative inline-block">
          {!glowOnly && char}
          {glowOnly && char}
          {!glowOnly && (
            <span
              aria-hidden
              data-bulb=""
              className="pointer-events-none absolute left-1/2 rounded-full transition-opacity duration-200 ease-out"
              style={{
                top: BULB_TOP,
                width: "0.09em",
                height: "0.09em",
                minWidth: 12,
                minHeight: 12,
                transform: "translate(-50%, -50%)",
                background: bulbColor,
              opacity: 0,
              }}
            />
          )}
        </span>
      );
    } else {
      chars.push(
        <span key={`${char}-${index}`} className="inline-block">
          {char}
        </span>
      );
    }
  }

  return chars;
}

export function SpotlightText({
  text,
  theme = "light",
  spotlightRadius = 120,
  fontSize,
  fontWeight = 800,
  letterSpacing = "-0.02em",
  showBulb = true,
  glowColors,
  as: Component = "span",
  className,
  style,
}: SpotlightTextProps) {
  const tokens = SPOTLIGHT_THEMES[theme];
  const resolvedFontSize = resolveFontSize(fontSize);

  const glowCore = glowColors?.core ?? tokens.glowCore;
  const glowMid = glowColors?.mid ?? tokens.glowMid;
  const bulbColor = glowColors?.bulb ?? tokens.bulb;

  const hasBulbChars = showBulb && [...text].some((c) => BULB_CHARS.has(c));

  const { containerRef, textLayerRef, isHovered, reducedMotion, handlers } =
    useSpotlightHover();

  const isActive = isHovered && hasBulbChars;

  const bulbCenters = useBulbPositions(textLayerRef, [
    text,
    resolvedFontSize,
    fontWeight,
    letterSpacing,
    showBulb,
  ]);

  const sharedTextStyle: CSSProperties = {
    fontSize: resolvedFontSize,
    fontWeight,
    letterSpacing,
    lineHeight: 1,
    fontFamily: "inherit",
    whiteSpace: "pre",
  };

  const containerStyle: CSSProperties = {
    background: tokens.surface,
    ...style,
  };

  const charOptions = useMemo(
    () => ({ showBulb, bulbColor, isActive }),
    [showBulb, bulbColor, isActive]
  );

  const baseCharacters = useMemo(
    () => renderCharacters(text, charOptions),
    [text, charOptions]
  );

  const glowCharacters = useMemo(
    () => renderCharacters(text, { ...charOptions, glowOnly: true, showBulb: false }),
    [text, charOptions]
  );

  const bulbGlowGradient = useMemo(() => {
    if (!isActive || bulbCenters.length === 0) return "none";
    return buildBulbGlowGradient(bulbCenters, spotlightRadius, glowCore, glowMid);
  }, [isActive, bulbCenters, spotlightRadius, glowCore, glowMid]);

  const baseShadow = `${tokens.debossHighlight}, ${tokens.debossShadow}`;

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative inline-flex items-center justify-center select-none px-8 py-10",
        className
      )}
      style={containerStyle}
      {...handlers}
    >
      <Component
        ref={textLayerRef}
        className="relative inline-block"
        style={sharedTextStyle}
      >
        {/* Base: debossed idle text + bulb markers for measurement */}
        <span
          className="relative z-[1] block"
          style={{
            ...sharedTextStyle,
            color: tokens.idleText,
            textShadow: baseShadow,
          }}
        >
          {baseCharacters}
        </span>

        {/* Glow: radiates from i/j bulbs, clipped strictly to glyph shapes */}
        {!reducedMotion && hasBulbChars && (
          <span
            aria-hidden
            className="pointer-events-none absolute left-0 top-0 z-[2] block overflow-hidden"
            style={{
              ...sharedTextStyle,
              color: "transparent",
              backgroundImage: bulbGlowGradient,
              WebkitBackgroundClip: "text",
              backgroundClip: "text",
              WebkitTextFillColor: "transparent",
              opacity: isActive ? 1 : 0,
              transition: "opacity 800ms cubic-bezier(0.16, 1, 0.3, 1)",
            }}
          >
            {glowCharacters}
          </span>
        )}

        {/* Reduced motion: static warm tint on glyphs only */}
        {reducedMotion && hasBulbChars && (
          <span
            aria-hidden
            className="pointer-events-none absolute left-0 top-0 z-[2] block"
            style={{
              ...sharedTextStyle,
              color: "transparent",
              backgroundImage: buildBulbGlowGradient(
                bulbCenters.length > 0
                  ? bulbCenters
                  : [{ x: 0, y: 0 }],
                spotlightRadius,
                glowCore,
                glowMid
              ),
              WebkitBackgroundClip: "text",
              backgroundClip: "text",
              WebkitTextFillColor: "transparent",
              opacity: 0.85,
            }}
          >
            {glowCharacters}
          </span>
        )}
      </Component>
    </div>
  );
}

import type { CSSProperties, ElementType } from "react";

export type SpotlightTextTheme = "light" | "dark";

export interface SpotlightGlowColors {
  core?: string;
  mid?: string;
  bulb?: string;
}

export interface SpotlightTextProps {
  /** Text to render */
  text: string;
  /** Surface and deboss palette */
  theme?: SpotlightTextTheme;
  /** Spotlight radius in px */
  spotlightRadius?: number;
  /** Display font size */
  fontSize?: string | number;
  fontWeight?: number;
  letterSpacing?: string;
  /** Glowing ascender-dot bulbs on i/j characters */
  showBulb?: boolean;
  /** Override theme glow colors */
  glowColors?: SpotlightGlowColors;
  /** Semantic HTML element */
  as?: ElementType;
  className?: string;
  style?: CSSProperties;
}

import type { SpotlightTextTheme } from "./types";

export interface SpotlightThemeTokens {
  surface: string;
  idleText: string;
  debossHighlight: string;
  debossShadow: string;
  glowCore: string;
  glowMid: string;
  bulb: string;
  bulbBloom: string;
  activeHighlight: string;
  activeShadow: string;
}

export const SPOTLIGHT_THEMES: Record<SpotlightTextTheme, SpotlightThemeTokens> = {
  light: {
    surface: "#eaeaea",
    idleText: "#b8b8b8",
    debossHighlight: "0 1px 0 rgba(255, 255, 255, 0.9)",
    debossShadow: "0 -1px 2px rgba(0, 0, 0, 0.15)",
    glowCore: "#ebd5ff",
    glowMid: "#a78bfa",
    bulb: "#c084fc",
    bulbBloom: "0 0 20px 10px rgba(167, 139, 250, 0.3), 0 0 40px 20px rgba(167, 139, 250, 0.1)",
    activeHighlight: "0 -1px 0 rgba(255, 255, 255, 0.4)",
    activeShadow: "0 2px 3px rgba(0, 0, 0, 0.2)",
  },
  dark: {
    surface: "#1a1a1a",
    idleText: "#454545",
    debossHighlight: "0 -1px 0 rgba(255, 255, 255, 0.06)",
    debossShadow: "0 2px 4px rgba(0, 0, 0, 0.6)",
    glowCore: "#ebd5ff",
    glowMid: "#a78bfa",
    bulb: "#c084fc",
    bulbBloom: "0 0 24px 12px rgba(167, 139, 250, 0.35), 0 0 48px 24px rgba(167, 139, 250, 0.12)",
    activeHighlight: "0 1px 0 rgba(255, 255, 255, 0.15)",
    activeShadow: "0 -2px 3px rgba(0, 0, 0, 0.5)",
  },
};
